type Score = { ticker: string; score: number; reasons: string[] };

export function scoreStock(r: StockRow): Score {
  let score = 0;
  const reasons: string[] = [];

  // liquidity proxy (nếu có valueTraded)
  if (r.valueTraded && typeof r.valueTraded.value === "number") {
    const v = r.valueTraded.value;
    if (v >= 50e9) { score += 2; reasons.push("GTGD cao"); }
    else if (v >= 20e9) { score += 1; reasons.push("GTGD đạt ngưỡng"); }
  }

  // trend proxy (nếu có MA20)
  if (r.ma20 && typeof r.close.value === "number" && typeof r.ma20.value === "number") {
    if (r.close.value > r.ma20.value) { score += 1; reasons.push("Giá > MA20"); }
  }

  // volume proxy
  if (typeof r.volume.value === "number") {
    // có thể so với vol20 nếu bạn enrich
    score += 0.5;
    reasons.push("Có thanh khoản");
  }

  return { ticker: r.ticker, score, reasons };
}

export function rank(rows: StockRow[]) {
  return rows
    .map(scoreStock)
    .sort((a, b) => b.score - a.score || a.ticker.localeCompare(b.ticker));
}

